#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    int n,count=0;    cin >> n;        vll a(n);    for(int i=0; i<n; i++){        cin >> a[i];        if(a[i]==2){            count++;        }    }    int count2=0;    bool found=false;    for(int i=0; i<n; i++){        if(a[i]==2){            count2++;                    }        if(count2==(count-count2)){            cout << i+1 << "\n";            found=true;            break;        }    }    if(found==false){        cout << -1 << "\n";    }           } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}